INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (0.0, 1, 2, "まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！", "vo_minigame_1012_result_1080", 3001, 12300148, 1, 5, 9, 1, 1, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (2.21, 1, 2, "うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！", "vo_minigame_1012_result_1081", 3001, 12300149, 1, 5, 9, 2, 8, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (2.46, 1, 2, "ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！", "vo_minigame_1012_result_1082", 3001, 12300150, 1, 5, 9, 2, 3, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (2.94, 1, 2, "ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？", "vo_minigame_1012_result_1083", 3001, 12300151, 1, 5, 9, 2, 3, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (4.19, 1, 2, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", "vo_minigame_1012_result_1084", 3001, 12300152, 1, 5, 9, 3, 7, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (0.0, 1, 2, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", "vo_minigame_1012_result_1085", 3001, 12300153, 1, 5, 9, 3, 1, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (2.63, 1, 2, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", "vo_minigame_1012_result_1086", 3001, 12300154, 1, 5, 9, 3, 3, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (5.53, 1, 2, "あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか", "vo_minigame_1012_result_1087", 3001, 12300155, 1, 1, 4, 1, 3, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (0.01, 3, 2, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", "vo_minigame_1012_result_1088", 3001, 12300156, 1, 1, 4, 1, 3, 9);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (4.15, 1, 2, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", "vo_minigame_1012_result_1089", 3001, 12300157, 1, 1, 4, 1, 3, 3);
