INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (4.29, 10, 2, "覚えても、すぐ忘れるんだけど\nどしたらいい？\nあ、そーゆうとき\nフクシューする感じ？", "vo_minigame_1012_result_2092", 3001, 22300160, 2, 1, 4, 2, 4, 3);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (4.64, 8, 2, "ムズ過ぎ！\n頭パンクするかと思った…！\nヒデサイ、うちの頭\nふぅふぅして～", "vo_minigame_1012_result_2093", 3001, 22300161, 2, 1, 4, 3, 4, 6);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (3.14, 5, 2, "おにムズ過ぎてテンサゲ～\nでもヒデサイがんばってるし\nうちもがんばる！", "vo_minigame_1012_result_2094", 3001, 22300162, 2, 1, 4, 3, 9, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (6.59, 4, 2, "ヒデサイと同じ点数で\nちょっち安心したかも\n一緒にがんばろーね！\n置いてっちゃやだよ？", "vo_minigame_1012_result_2095", 3001, 22300163, 2, 1, 4, 3, 7, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (0.0, 3, 2, "…まあ、これより下はないし\n次は大逆転\n点数爆上がりっしょ！", "vo_minigame_1012_result_2096", 3001, 22300164, 2, 0, 0, 1, 3, 0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (2.2, 10, 2, "０点じゃん…\nそだ、次はえんぴつ転がして\n選ぶ作戦やってみる？", "vo_minigame_1012_result_2097", 3001, 22300165, 2, 0, 0, 1, 9, 5);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (0.01, 4, 2, "考えるの無理な時あるよね…\nヒデサイもそーゆう\n感じだったの？", "vo_minigame_1012_result_2098", 3001, 22300166, 2, 0, 0, 1, 4, 6);
